{
  "pregunta": "¿Cómo me inscribo si soy extranjero con residencia temporaria?",
  "respuesta": "Sí, puedes recibir asesoría. Solo necesitas tu cédula de identidad chilena vigente o pasaporte y tu idea de negocio o iniciación de actividades."
}

{
  "faq": [
    {
      "id": "faq-1",
      "pregunta": "¿Qué comunas atiende el Centro de Negocios Santiago?",
      "respuesta": "Atendemos a cooperativas, pymes y emprendimientos con dirección comercial o residencia en Santiago y Providencia."
    },
    {
      "id": "faq-2",
      "pregunta": "¿Las mentorías y capacitaciones tienen costo?",
      "respuesta": "No. Todo es 100% gratuito. Sercotec es un servicio público de fomento productivo patrocinado por el Ministerio de Economía."
    },
    {
      "id": "faq-3",
      "pregunta": "¿Dónde atienden presencialmente?",
      "respuesta": "Nuestra oficina principal está en Manuel Rodríguez Sur 749 (Metro Toesca) y oficina satélite en Los Jesuitas 881, Providencia."
    }
  ]
}

